#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool is_end_of_word;
    TrieNode() : is_end_of_word(false) {}
};

class Solution {
public:
    Solution() : root(new TrieNode()) {}
    ~Solution() { destroy(root); }

    void insert(string word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                node->children[c] = new TrieNode();
            }
            node = node->children[c];
        }
        node->is_end_of_word = true;
    }

    bool search(string word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                return false;
            }
            node = node->children[c];
        }
        return node->is_end_of_word;
    }

    bool startsWith(string prefix) {
        TrieNode* node = root;
        for (char c : prefix) {
            if (node->children.find(c) == node->children.end()) {
                return false;
            }
            node = node->children[c];
        }
        return true;
    }

    void deleteWord(string word) {
        deleteWord(root, word, 0);
    }

private:
    TrieNode* root;

    bool deleteWord(TrieNode*& node, string& word, int index) {
        if (index == word.size()) {
            if (!node->is_end_of_word) {
                return false;
            }
            node->is_end_of_word = false;
            return node->children.empty();
        }
        char c = word[index];
        if (node->children.find(c) == node->children.end()) {
            return false;
        }
        bool should_delete_current_node = deleteWord(node->children[c], word, index + 1);
        if (should_delete_current_node) {
            delete node->children[c];
            node->children.erase(c);
            return node->children.empty() && !node->is_end_of_word;
        }
        return false;
    }

    void destroy(TrieNode* node) {
        if (!node) return;
        for (auto& child : node->children) {
            destroy(child.second);
        }
        delete node;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    Solution sol;
    cin.ignore();
    for (int i = 0; i < n; ++i) {
        string line;
        getline(cin, line);
        size_t space_pos = line.find(' ');
        string op = line.substr(0, space_pos);
        string arg = line.substr(space_pos + 1);
        if (op == "insert") {
            sol.insert(arg);
        } else if (op == "search") {
            cout << (sol.search(arg) ? "true" : "false") << '\n';
        } else if (op == "startsWith") {
            cout << (sol.startsWith(arg) ? "true" : "false") << '\n';
        } else if (op == "delete") {
            sol.deleteWord(arg);
        }
    }
    return 0;
}
